import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { describe, expect, it } from "vitest";
import { Tooltip } from "./Tooltip";

describe("Tooltip", () => {
  it("describes an asChild trigger on hover and focus", async () => {
    const user = userEvent.setup();

    render(
      <Tooltip asChild content="Helpful context">
        <button type="button">Info</button>
      </Tooltip>,
    );

    const trigger = screen.getByRole("button", { name: "Info" });

    await user.hover(trigger);
    const tooltip = await screen.findByRole("tooltip");

    expect(tooltip).toHaveTextContent("Helpful context");
    expect(trigger).toHaveAttribute("aria-describedby", tooltip.id);
    expect(trigger).toHaveAccessibleDescription("Helpful context");

    await user.unhover(trigger);
    expect(screen.queryByRole("tooltip")).not.toBeInTheDocument();
    expect(trigger).not.toHaveAttribute("aria-describedby");

    await user.tab();
    expect(trigger).toHaveFocus();
    expect(await screen.findByRole("tooltip")).toHaveTextContent("Helpful context");
    expect(trigger).toHaveAccessibleDescription("Helpful context");
  });

  it("preserves existing descriptions while the tooltip opens and closes", async () => {
    const user = userEvent.setup();

    render(
      <>
        <p id="external-note">Visible note</p>
        <Tooltip asChild content="Helpful context">
          <button aria-describedby="external-note" type="button">
            Info
          </button>
        </Tooltip>
        <button type="button">Next</button>
      </>,
    );

    const trigger = screen.getByRole("button", { name: "Info" });

    expect(trigger).toHaveAccessibleDescription("Visible note");

    await user.tab();

    const tooltip = await screen.findByRole("tooltip");
    expect(trigger).toHaveFocus();
    expect(trigger).toHaveAttribute(
      "aria-describedby",
      `external-note ${tooltip.id}`,
    );
    expect(trigger).toHaveAccessibleDescription(
      "Visible note Helpful context",
    );

    await user.tab();

    expect(screen.getByRole("button", { name: "Next" })).toHaveFocus();
    expect(screen.queryByRole("tooltip")).not.toBeInTheDocument();
    expect(trigger).toHaveAttribute("aria-describedby", "external-note");
    expect(trigger).toHaveAccessibleDescription("Visible note");
  });
});

"use client";

import {
  HTMLAttributes,
  ReactNode,
  forwardRef,
  useCallback,
  useId,
  useRef,
  useState,
} from "react";
import { createPortal } from "react-dom";
import { Slot, cn, swirskiAttrs } from "../../system";
import { useFloatingPosition } from "../../system/floating";
import { usePortalRoot } from "../../hooks/use-portal-root/usePortalRoot";

export type TooltipVariant = "default";
export type TooltipSize = "sm" | "md";
export type TooltipTone = "black" | "yellow";

export type TooltipProps = {
  asChild?: boolean;
  children: ReactNode;
  content: ReactNode;
  variant?: TooltipVariant;
  size?: TooltipSize;
  tone?: TooltipTone;
} & HTMLAttributes<HTMLSpanElement>;

const sizeStyles: Record<TooltipSize, string> = {
  sm: "px-2 py-1 text-[0.65rem] leading-4",
  md: "px-3 py-2 text-xs leading-5",
};

const toneStyles: Record<TooltipTone, string> = {
  black: "bg-[#0B0B0C] text-white shadow-[5px_5px_0_#FFD400]",
  yellow: "bg-[#FFD400] text-black shadow-[5px_5px_0_#0B0B0C]",
};

export const Tooltip = forwardRef<HTMLSpanElement, TooltipProps>(
  function Tooltip(
    {
      asChild = false,
      children,
      content,
      className,
      onBlur,
      onFocus,
      onPointerEnter,
      onPointerLeave,
      variant = "default",
      size = "md",
      tone = "black",
      ...props
    },
    ref,
  ) {
    const Component = asChild ? Slot : "span";
    const triggerRef = useRef<HTMLElement | null>(null);
    const tooltipRef = useRef<HTMLSpanElement | null>(null);
    const tooltipId = `${useId()}-tooltip`;
    const portalRoot = usePortalRoot();
    const [hovered, setHovered] = useState(false);
    const [focused, setFocused] = useState(false);
    const open = hovered || focused;
    const tooltipStyle = useFloatingPosition({
      floatingRef: tooltipRef,
      open,
      placement: "top",
      referenceRef: triggerRef,
    });
    const describedBy =
      [props["aria-describedby"], open ? tooltipId : undefined]
        .filter(Boolean)
        .join(" ") || undefined;

    const setTriggerRef = useCallback(
      (node: HTMLElement | null) => {
        triggerRef.current = node;

        if (typeof ref === "function") {
          ref(node as HTMLSpanElement | null);
          return;
        }

        if (ref) {
          ref.current = node as HTMLSpanElement | null;
        }
      },
      [ref],
    );

    const tooltipContent =
      open &&
      portalRoot &&
      createPortal(
        <span
          ref={tooltipRef}
          className={cn(
            "pointer-events-none fixed z-[1000] w-max max-w-[calc(100vw-1.5rem)] border-4 border-black font-black uppercase",
            sizeStyles[size],
            toneStyles[tone],
          )}
          id={tooltipId}
          role="tooltip"
          style={tooltipStyle}
          {...swirskiAttrs("tooltip-content", { size, tone, variant })}
        >
          {content}
        </span>,
        portalRoot,
      );

    return (
      <>
        <Component
          ref={setTriggerRef}
          className={cn("group relative inline-flex", className)}
          {...swirskiAttrs("tooltip", { size, tone, variant })}
          {...props}
          aria-describedby={describedBy}
          onBlur={(event) => {
            onBlur?.(event);
            setFocused(false);
          }}
          onFocus={(event) => {
            onFocus?.(event);
            setFocused(true);
          }}
          onPointerEnter={(event) => {
            onPointerEnter?.(event);
            setHovered(true);
          }}
          onPointerLeave={(event) => {
            onPointerLeave?.(event);
            setHovered(false);
          }}
        >
          {children}
        </Component>
        {tooltipContent}
      </>
    );
  },
);

Tooltip.displayName = "Tooltip";

export { Tooltip } from "./Tooltip";
export type {
  TooltipProps,
  TooltipSize,
  TooltipTone,
  TooltipVariant,
} from "./Tooltip";
